mapper.select:
SELECT
    id, employee_no, username, name, nickname, avatar, gender,
    phone_number, email, job_title, department_id,
    hide_phone_number, hide_name, remark, status,
    created_at, updated_at, created_by, updated_by
FROM sys_user
WHERE deleted = 0


    AND (
        name LIKE CONCAT('%', #{keyword}, '%')
        OR employee_no LIKE CONCAT('%', #{keyword}, '%')
        OR phone_number LIKE CONCAT('%', #{keyword}, '%')
    )



    AND employee_no LIKE CONCAT(#{employeeNo}, '%')



    AND name LIKE CONCAT('%', #{name}, '%')



    AND phone_number = #{phoneNumber}



    AND status = #{status}



    AND department_id = #{departmentId}



    AND job_title LIKE CONCAT('%', #{jobTitle}, '%')



    AND gender = #{gender}



    AND created_at >= #{createdAtStart}


    AND created_at <= #{createdAtEnd}

ORDER BY created_at DESC
